import os
import logging
from logging.handlers import RotatingFileHandler

# Create the log directory if it doesn't exist
log_dir = '/var/log/application'
os.makedirs(log_dir, exist_ok=True)

# Set up basic configuration for logging
logging.basicConfig(level=logging.DEBUG)

# Create a rotating file handler that logs to /var/log/application/app.log
file_handler = RotatingFileHandler(os.path.join(log_dir, 'app.log'), maxBytes=1024*1024*5, backupCount=3)
file_handler.setLevel(logging.INFO)

# Set up formatter for the log messages
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
file_handler.setFormatter(formatter)

# Add the file handler to the root logger
logging.getLogger('').addHandler(file_handler)

# Example usage of the logger
logging.info('This is an info message')